<?php
namespace App\Services\Orders;use App\Models\{Order,OrderCompletionProof,User};use Illuminate\Validation\ValidationException;class OrderCompletionService{public function canSubmitProof(Order $o,User $w):array{$assigned=$o->dispatchAssignments()->where('assigned_user_id',$w->id)->whereIn('status',['assigned','accepted'])->first();$duplicate=$o->completionProofs()->whereIn('status',['submitted','accepted'])->exists();$allowed=$assigned&&$o->status->value==='in_progress'&&!$duplicate;return ['allowed'=>(bool)$allowed,'reason'=>!$assigned?'Worker is not assigned to this order.':($o->status->value!=='in_progress'?'Order is not in progress.':($duplicate?'An active completion proof already exists.':null))];}public function submitProof(Order $o,User $w,array $d):OrderCompletionProof{$x=$this->canSubmitProof($o,$w);throw_unless($x['allowed'],ValidationException::withMessages(['proof'=>$x['reason']]));$p=$o->completionProofs()->create(['dispatch_assignment_id'=>$o->activeDispatchAssignment()?->id,'worker_id'=>$w->id,'status'=>'submitted','proof_type'=>'text','worker_note'=>$d['worker_note'],'submitted_at'=>now()]);$this->event($p,$w,'submitted','Worker submitted text completion proof.');return $p;}public function acceptByCustomer(OrderCompletionProof $p,User $c,?string $note):OrderCompletionProof{$this->customer($p,$c);throw_unless($p->status==='submitted',ValidationException::withMessages(['proof'=>'Only submitted proof can be accepted.']));$p->update(['status'=>'accepted','customer_note'=>$note,'accepted_at'=>now(),'reviewed_by_customer_id'=>$c->id]);$this->event($p,$c,'accepted_by_customer','Customer accepted completion proof.');return $p;}public function disputeByCustomer(OrderCompletionProof $p,User $c,string $reason):OrderCompletionProof{$this->customer($p,$c);throw_unless($p->status==='submitted',ValidationException::withMessages(['proof'=>'Only submitted proof can be disputed.']));$p->update(['status'=>'disputed','customer_note'=>$reason,'disputed_at'=>now(),'reviewed_by_customer_id'=>$c->id]);$this->event($p,$c,'disputed_by_customer','Customer disputed completion proof.');return $p;}public function getCompletionState(Order $o):array{$p=$o->completionProofs()->latest()->first();return ['proof'=>$p,'status'=>$p?->status??'not_submitted','payout_blockers'=>$this->getPayoutBlockers($o)];}public function getPayoutBlockers(Order $o):array{$p=$o->completionProofs()->latest()->first();$b=[];if(!$p||$p->status!=='accepted')$b[]='Completion proof is not accepted by customer.';if(!$o->paymentRecords()->where('status','captured')->exists())$b[]='Payment is not captured.';return $b;}private function customer(OrderCompletionProof $p,User $c):void{abort_unless($p->order()->where('customer_id',$c->id)->exists(),404);}private function event(OrderCompletionProof $p,User $a,string $type,string $description):void{$p->events()->create(['order_id'=>$p->order_id,'actor_id'=>$a->id,'event_type'=>$type,'description'=>$description,'created_at'=>now()]);}}
